import fs from 'fs'
import { build as viteBuild } from 'vite'
import { getBaseViteConfig } from './vite.js'

export async function build() {
    if (!fs.existsSync('./scenes')) {
        console.log('No scenes folder found. Are you inside a maki game folder?')
        console.log('Try: maki new my-game && cd my-game && maki build')
        return
    }

    console.log('🍣 Building Maki game...')

    await viteBuild({
        ...getBaseViteConfig(),
        build: {
            outDir: 'dist',
            emptyOutDir: true,
        }
    })

    console.log('🍣 Build complete in ./dist')
}